// ── User ───────────────────────────────────────────────────────────────

public class UserTests
{
    /// <summary>Returns a pre-filled User instance for use in tests.</summary>
    public static User MakeSampleUser()
    {
        return new User
        {
            Tags = new Dictionary<string, string> { { "hello", "hello" } },
            UserSession = "hello",
            UserName = "hello",
            UserID = 42U,
        };
    }

    /// <summary>
    /// Returns a User with only scalar value-like fields populated.
    /// Strings, bytes, collections, and nested messages remain at default values.
    /// </summary>
