    {
        var m = new User();
        Assert.Equal(0, m.ProtobufSize());
    }

    [Fact]
    public void Empty_ToProtobuf_WritesNothing()
    {
        var m = new User();
        var buf = new RentedBuffer(16);
        m.ToProtobuf(ref buf);
        Assert.Equal(0, buf.Length);
        buf.Dispose();
    }

