    // Verifies that serialising a populated User and deserialising it
    // into a ReadonlyUser, then cloning back to a writer, produces byte-identical
    // protobuf output (lossless roundtrip).
    [Fact]
    public void ProtobufRoundtrip()
    {
        var w = MakeSampleUser();
        int sz = w.ProtobufSize();
        var buf = new RentedBuffer(sz + 4);
        w.ToProtobuf(ref buf);
        Assert.Equal(sz, buf.Length);

        var r = new ReadonlyUser();
        var err = r.FromProtobuf(buf.AsSpan());
        Assert.False(err.Err());

        var w2 = new User();
        r.Clone(ref w2);
        var buf2 = new RentedBuffer(w2.ProtobufSize() + 4);
        w2.ToProtobuf(ref buf2);

        Assert.Equal(buf.AsSpan().ToArray(), buf2.AsSpan().ToArray());
        buf.Dispose();
        buf2.Dispose();
    }

