        Assert.False(err.Err());

        var w2 = new User();
        r.Clone(ref w2);
        var jBuf2 = new RentedBuffer(256);
        w2.ToJSON(ref jBuf2);

        Assert.Equal(json, jBuf2.AsSpan().ToArray());
        jBuf.Dispose();
        jBuf2.Dispose();
    }

